const ERRORS = {
    INVALID_APP_URL: {
        type: INVALID_APP_URL,
        code: BAD_USER_INPUT,
        message: 'App url is not a valid URL',
        messageForUser: 'api.miniapp.B2BApp.appUrl.INVALID_URL',
    },
    HTTPS_ONLY_ALLOWED: {
        type: INVALID_APP_URL,
        code: BAD_USER_INPUT,
        message: 'App url must use https protocol',
        messageForUser: 'api.miniapp.B2BApp.appUrl.HTTPS_ONLY_ALLOWED',
    },
    LOCALHOST_NOT_ALLOWED: {
        type: INVALID_APP_URL,
        code: BAD_USER_INPUT,
        message: 'App url must not be localhost',
        messageForUser: 'api.miniapp.B2BApp.appUrl.LOCALHOST_NOT_ALLOWED',
    },
    SPECIAL_IP_NOT_ALLOWED: {
        type: INVALID_APP_URL,
        code: BAD_USER_INPUT,
        message: 'App url must not be private / special IP address',
        messageForUser: 'api.miniapp.B2BApp.appUrl.SPECIAL_IP_NOT_ALLOWED',
    },
}


const B2BApp = new GQLListSchema('B2BApp', {
    schemaDoc: 'B2B application',
    fields: {
        name: {
            schemaDoc: 'Name of application',
            type: 'Text',
            isRequired: true,
        },
        developer: {
            schemaDoc: 'Developer company name which will be exported. If not specified, creator name will be taken',
            type: 'Text',
            isRequired: false,
        },
        developerUrl: {
            schemaDoc: 'Developer company URL which will be shown on app page',
            type: 'Text',
            isRequired: false,
        },
        logo: {
            schemaDoc: 'Icon of application. Accepted mime types: ["image/png", "image/jpeg", "image/webp"]',
            type: 'File',
            isRequired: false,
            adapter: LOGO_FILE_ADAPTER,
            hooks: {
                validateInput: getMimeTypesValidator({ allowedTypes: ['image/png', 'image/jpeg', 'image/webp'] }),
            },
        },
        shortDescription: {
            shortDescription: 'Short text description of application shown on its card in apps catalog',
            type: 'Text',
            isRequired: false,
        },
        detailedDescription: {
            schemaDoc:
                'Detailed markdown description of application shown on its page. ' +
                'Used to describe apps functionality, pricing, etc',
            type: 'Markdown',
            isRequired: false,
        },
        category: {
            schemaDoc: `Category of app. Can be one of the following: [${B2B_APP_CATEGORIES.map(category => `"${category}"`).join(', ')}] By default set to "${OTHER_CATEGORY}"`,
            type: 'Select',
            dataType: 'string',
            isRequired: true,
            options: B2B_APP_CATEGORIES,
            defaultValue: OTHER_CATEGORY,
        },
        ...getEnvironmentalFields('appUrl', {
            schemaDoc: 'Web app entrypoint URL for {environment} environment, which is used to open app in WebView or IFrame',
            type: 'Url',
            isRequired: false,
            hooks: {
                async validateInput ({ resolvedData, fieldPath, context }) {
                    const value = resolvedData[fieldPath]
                    if (value === null) return

                    const urlMeta = getUrlMeta(value)
                    if (!urlMeta) {
                        throw new GQLError(ERRORS.INVALID_APP_URL, context)
                    }
                    if (urlMeta.protocol !== 'https:') {
                        throw new GQLError(ERRORS.HTTPS_ONLY_ALLOWED, context)
                    }
                    if (urlMeta.isLocalhost) {
                        throw new GQLError(ERRORS.LOCALHOST_NOT_ALLOWED, context)
                    }
                    if (urlMeta.isSpecialIP) {
                        throw new GQLError(ERRORS.SPECIAL_IP_NOT_ALLOWED, context)
                    }
                },
            },
        }),
        ...getEnvironmentalFields('oidcClientId', OIDC_CLIENT_ID_FIELD),
        ...getEnvironmentalPermissionsFields({ listKey: 'B2BApp' }),
        ...getEnvironmentalFields('publishedAt', {
            schemaDoc: 'The last time a mini-app was published on the {environment} environment',
            type: 'DateTimeUtc',
            kmigratorOptions: { db_index: true },
            access: {
                read: true,
                create: false,
                // NOTE: function used to make it appear in B2CAppUpdateInput
                update: () => false,
            },
        }),
    },
    hooks: {
        afterChange: LOGO_META_AFTER_CHANGE,
        validateInput: getSharedConstraintsValidator(['B2CApp']),
    },
    plugins: [uuided(), versioned(), tracked(), softDeleted(), dvAndSender(), exportable(), historical(), analytical()],
    access: {
        read: canReadAppSchemas,
        create: canManageAppSchemas,
        update: canManageAppSchemas,
        delete: false,
        auth: true,
    },
})

